module d_flip_flop (  
    input wire clk,  
    input wire rst,  
    input wire en,  
    input wire d,  
    output reg q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (rst)  
            q <= 0;  
        else if (en)  
            q <= d;  
    end  
endmodule
